6	//! CUDA context management (primary context, RAII).
7	//!
8	//! [`CudaContext`] retains the **primary context** for a given device ordinal
9	//! via `cuDevicePrimaryCtxRetain` and releases it on [`Drop`]. The primary
10	//! context is shared across the process; multiple `CudaContext` instances for
11	//! the same device share the same underlying `CUcontext`.
12	//!
13	//! # Thread binding
14	//!
15	//! CUDA driver calls are context-scoped and thread-local. [`CudaContext`]
16	//! transparently calls `cuCtxSetCurrent` before any driver operation, so
17	//! callers do not need to manage the context stack manually.
18	
19	use crate::error::{DriverError, IntoResult};
20	use crate::stream::CudaStream;
21	use std::ffi::c_int;
22	use std::mem::MaybeUninit;
23	use std::sync::Arc;
24	use std::sync::atomic::{AtomicBool, AtomicU32, AtomicUsize, Ordering};
25	
26	/// Owns a reference to a CUDA device's primary context.
27	///
28	/// Created via [`CudaContext::new`] and typically held in an `Arc` so streams,
29	/// events, and modules can share the same context. Dropping the last reference
30	/// releases the primary context (`cuDevicePrimaryCtxRelease`).
31	///
32	/// Tracks live stream count and accumulated error state atomically for
33	/// cross-thread diagnostics.
34	#[derive(Debug)]
35	pub struct CudaContext {
36	    /// Raw CUDA device handle (`CUdevice`).
37	    pub(crate) cu_device: cuda_bindings::CUdevice,
38	    /// Raw CUDA context handle (`CUcontext`). Set to null on drop.
39	    pub(crate) cu_ctx: cuda_bindings::CUcontext,
40	    /// Zero-based device ordinal passed to [`CudaContext::new`].
41	    pub(crate) ordinal: usize,
42	    /// Number of live [`CudaStream`] instances sharing this context.
43	    pub(crate) num_streams: AtomicUsize,
44	    /// When `true`, the first [`new_stream`](CudaContext::new_stream) call
45	    /// synchronizes the context to establish a clean ordering baseline.
46	    pub(crate) event_tracking: AtomicBool,
47	    /// Sticky error state recorded by [`record_err`](CudaContext::record_err).
48	    /// Stores the raw `CUresult` value, or `0` if no error.
49	    pub(crate) error_state: AtomicU32,
50	}
51	
52	/// # Safety
53	///
54	/// `CUdevice` and `CUcontext` are process-wide handles. All mutable state
55	/// (`num_streams`, `event_tracking`, `error_state`) uses atomics. The CUDA
56	/// driver itself is thread-safe for distinct contexts, and the
57	/// [`bind_to_thread`](CudaContext::bind_to_thread) mechanism ensures the
58	/// correct context is current before each call.
59	unsafe impl Send for CudaContext {}
60	/// See [`Send`] impl.
61	unsafe impl Sync for CudaContext {}
62	
63	/// Releases the primary context on drop.
64	///
65	/// Binds the context to the current thread first (required by
66	/// `cuDevicePrimaryCtxRelease`). Errors during teardown are recorded via
67	/// [`record_err`](CudaContext::record_err) rather than panicking.
68	impl Drop for CudaContext {
69	    fn drop(&mut self) {
70	        self.record_err(self.bind_to_thread());
71	        let ctx = std::mem::replace(&mut self.cu_ctx, std::ptr::null_mut());
72	        if !ctx.is_null() {
73	            self.record_err(unsafe {
74	                cuda_bindings::cuDevicePrimaryCtxRelease_v2(self.cu_device).result()
75	            });
76	        }
77	    }
78	}
79	
80	/// Equality is based on device handle, context handle, and ordinal.
81	impl PartialEq for CudaContext {
82	    fn eq(&self, other: &Self) -> bool {
83	        self.cu_device == other.cu_device
84	            && self.cu_ctx == other.cu_ctx
85	            && self.ordinal == other.ordinal
86	    }
87	}
88	impl Eq for CudaContext {}
89	
90	impl CudaContext {
91	    /// Creates a new context for the device at `ordinal`.
92	    ///
93	    /// Calls [`cuInit`](crate::init), obtains the device handle, retains the
94	    /// primary context, and binds it to the calling thread. Returns the context
95	    /// wrapped in an `Arc` for shared ownership across streams, events, and
96	    /// modules.
97	    pub fn new(ordinal: usize) -> Result<Arc<Self>, DriverError> {
98	        unsafe { crate::init(0)? };
99	
100	        let cu_device = unsafe {
101	            let mut cu_device = MaybeUninit::uninit();
102	            cuda_bindings::cuDeviceGet(cu_device.as_mut_ptr(), ordinal as c_int).result()?;
103	            cu_device.assume_init()
104	        };
105	
106	        let cu_ctx = unsafe {
107	            let mut cu_ctx = MaybeUninit::uninit();
108	            cuda_bindings::cuDevicePrimaryCtxRetain(cu_ctx.as_mut_ptr(), cu_device).result()?;
109	            cu_ctx.assume_init()
110	        };
111	
112	        let ctx = Arc::new(CudaContext {
113	            cu_device,
114	            cu_ctx,
115	            ordinal,
116	            num_streams: AtomicUsize::new(0),
117	            event_tracking: AtomicBool::new(true),
118	            error_state: AtomicU32::new(0),
119	        });
120	        ctx.bind_to_thread()?;
121	        Ok(ctx)
122	    }
123	
124	    /// Returns the zero-based device ordinal.
125	    pub fn ordinal(&self) -> usize {
126	        self.ordinal
127	    }
128	
129	    /// Returns the raw `CUdevice` handle.
130	    pub fn cu_device(&self) -> cuda_bindings::CUdevice {
131	        self.cu_device
132	    }
133	
134	    /// Returns the raw `CUcontext` handle.
135	    pub fn cu_ctx(&self) -> cuda_bindings::CUcontext {
136	        self.cu_ctx
137	    }
138	
139	    /// Binds this context to the calling thread if not already current.
140	    ///
141	    /// Checks [`check_err`](Self::check_err) first and propagates any sticky
142	    /// error. Skips the `cuCtxSetCurrent` call when the context is already
143	    /// bound, avoiding an unnecessary driver round-trip.
144	    ///
145	    /// Most methods on [`CudaStream`], [`CudaEvent`](crate::CudaEvent), and
146	    /// [`CudaModule`](crate::CudaModule) call this internally.
147	    ///
148	    /// CUcontext is the backing runtime object, and CUmodule / CUfunction / CUstream
149	    /// are opaque handles to objects created under that context. bind_to_thread()
150	    /// makes that context, the one, the current host thread is operating against.
151	    /// If the thread is currently bound to some other context, using those handles
152	    /// can fail.
153	    pub fn bind_to_thread(&self) -> Result<(), DriverError> {
154	        self.check_err()?;
155	        let mut current = MaybeUninit::uninit();
156	        unsafe {
157	            cuda_bindings::cuCtxGetCurrent(current.as_mut_ptr()).result()?;
158	            let current = current.assume_init();
159	            if current.is_null() || current != self.cu_ctx {
160	                cuda_bindings::cuCtxSetCurrent(self.cu_ctx).result()?;
161	            }
162	        }
163	        Ok(())
164	    }
165	
166	    /// Blocks the calling thread until all preceding work in this context
167	    /// completes.
168	    ///
169	    /// Binds the context first, then calls `cuCtxSynchronize`.
170	    pub fn synchronize(&self) -> Result<(), DriverError> {
171	        self.bind_to_thread()?;
172	        unsafe { cuda_bindings::cuCtxSynchronize() }.result()
173	    }
174	
175	    /// Returns a handle to the per-context default stream (stream `0`).
176	    ///
177	    /// The default stream implicitly synchronizes with all blocking streams in
178	    /// the same context. The returned [`CudaStream`] holds a null `CUstream`
179	    /// pointer, which the driver interprets as the default stream.
180	    pub fn default_stream(self: &Arc<Self>) -> Arc<CudaStream> {
181	        Arc::new(CudaStream {
182	            cu_stream: std::ptr::null_mut(),
183	            ctx: self.clone(),
184	        })
185	    }
186	
187	    /// Creates a new non-blocking stream in this context.
188	    ///
189	    /// The stream is created with `CU_STREAM_NON_BLOCKING`, so it does not
190	    /// implicitly synchronize with the default stream.
191	    ///
192	    /// On the first call (when `num_streams` transitions from 0 to 1), the
193	    /// context is synchronized to establish a clean ordering baseline if
194	    /// `event_tracking` is enabled.
195	    pub fn new_stream(self: &Arc<Self>) -> Result<Arc<CudaStream>, DriverError> {
196	        self.bind_to_thread()?;
197	        let prev = self.num_streams.fetch_add(1, Ordering::Relaxed);
198	        if prev == 0 && self.event_tracking.load(Ordering::Relaxed) {
199	            self.synchronize()?;
200	        }
201	        let mut cu_stream = MaybeUninit::uninit();
202	        let cu_stream = unsafe {
203	            cuda_bindings::cuStreamCreate(
204	                cu_stream.as_mut_ptr(),
205	                cuda_bindings::CUstream_flags_enum_CU_STREAM_NON_BLOCKING,
206	            )
207	            .result()?;
208	            cu_stream.assume_init()
209	        };
210	        Ok(Arc::new(CudaStream {
211	            cu_stream,
212	            ctx: self.clone(),
213	        }))
214	    }
215	
216	    /// Queries the device's marketing name (e.g. `"NVIDIA GeForce RTX 5090"`).
217	    ///
218	    /// Wraps `cuDeviceGetName` with a 256-byte buffer (driver guarantees
219	    /// the name fits in 256 bytes including the trailing NUL). Returns the
220	    /// decoded UTF-8 string with any trailing NULs stripped.
221	    pub fn device_name(&self) -> Result<String, DriverError> {
222	        self.bind_to_thread()?;
223	        let mut buf = [0; 256];
224	        unsafe {
225	            cuda_bindings::cuDeviceGetName(buf.as_mut_ptr(), buf.len() as c_int, self.cu_device)
226	                .result()?;
227	        }
228	        let bytes: Vec<u8> = buf
229	            .iter()
230	            .take_while(|&&c| c != 0)
231	            .map(|&c| c as u8)
232	            .collect();
233	        Ok(String::from_utf8_lossy(&bytes).into_owned())
234	    }
235	
236	    /// Queries the compute capability (SM version) of the device.
237	    ///
238	    /// Returns `(major, minor)` -- e.g. `(9, 0)` for Hopper H100.
239	    pub fn compute_capability(&self) -> Result<(i32, i32), DriverError> {
240	        self.bind_to_thread()?;
241	        let mut major = MaybeUninit::uninit();
242	        let mut minor = MaybeUninit::uninit();
243	        unsafe {
244	            cuda_bindings::cuDeviceGetAttribute(
245	                major.as_mut_ptr(),
246	                cuda_bindings::CUdevice_attribute_enum_CU_DEVICE_ATTRIBUTE_COMPUTE_CAPABILITY_MAJOR,
247	                self.cu_device,
248	            )
249	            .result()?;
250	            cuda_bindings::cuDeviceGetAttribute(
251	                minor.as_mut_ptr(),
252	                cuda_bindings::CUdevice_attribute_enum_CU_DEVICE_ATTRIBUTE_COMPUTE_CAPABILITY_MINOR,
253	                self.cu_device,
254	            )
255	            .result()?;
256	            Ok((major.assume_init(), minor.assume_init()))
257	        }
258	    }
259	
260	    /// Atomically reads and clears the sticky error state.
261	    ///
262	    /// Returns `Ok(())` if no error was recorded, or the stored
263	    /// [`DriverError`] otherwise. The error is cleared after this call.
264	    pub fn check_err(&self) -> Result<(), DriverError> {
265	        let error_state = self.error_state.swap(0, Ordering::Relaxed);
266	        if error_state == 0 {
267	            Ok(())
268	        } else {
269	            Err(DriverError(error_state))
270	        }
271	    }
272	
273	    /// Records a driver error into the sticky error state.
274	    ///
275	    /// Used during [`Drop`] paths where returning a `Result` is not possible.
276	    /// If `result` is `Err`, the raw error code is stored; subsequent
277	    /// [`check_err`](Self::check_err) or [`bind_to_thread`](Self::bind_to_thread)
278	    /// calls will surface it. A later store overwrites an earlier one.
279	    pub fn record_err<T>(&self, result: Result<T, DriverError>) {
280	        if let Err(err) = result {
281	            self.error_state.store(err.0, Ordering::Relaxed)
282	        }
283	    }
284	}
