72	impl CudaStream {
73	    /// Returns the raw `CUstream` handle (null for the default stream).
74	    pub fn cu_stream(&self) -> cuda_bindings::CUstream {
75	        self.cu_stream
76	    }
77	
78	    /// Returns the parent [`CudaContext`].
79	    pub fn context(&self) -> &Arc<CudaContext> {
80	        &self.ctx
81	    }
