131	    pub fn record_event(
132	        &self,
133	        flags: Option<cuda_bindings::CUevent_flags>,
134	    ) -> Result<CudaEvent, DriverError> {
135	        let event = self.ctx.new_event(flags)?;
136	        event.record(self)?;
137	        Ok(event)
138	    }
