171	    pub fn launch_host_function<F: FnOnce() + Send>(
172	        &self,
173	        host_func: F,
174	    ) -> Result<(), DriverError> {
175	        let boxed = Box::new(host_func);
176	        unsafe {
177	            cuda_bindings::cuLaunchHostFunc(
178	                self.cu_stream,
179	                Some(Self::callback_wrapper::<F>),
180	                Box::into_raw(boxed) as *mut c_void,
181	            )
182	            .result()
183	        }
184	    }
185	
186	    /// `extern "C"` trampoline invoked by the CUDA driver on a driver-internal
187	    /// thread when a host function callback fires.
188	    ///
189	    /// Reconstructs the `Box<F>` from the raw pointer and calls the closure.
190	    /// Panics are caught with `catch_unwind` to prevent unwinding across the
