197	    /// - Must be called exactly once per enqueued callback (double-free
198	    ///   otherwise).
199	    unsafe extern "C" fn callback_wrapper<F: FnOnce() + Send>(callback: *mut c_void) {
200	        let _ = std::panic::catch_unwind(|| {
201	            let callback: Box<F> = unsafe { Box::from_raw(callback as *mut F) };
