1	/*
2	 * SPDX-FileCopyrightText: Copyright (c) 2026 NVIDIA CORPORATION & AFFILIATES. All rights reserved.
3	 * SPDX-License-Identifier: Apache-2.0
4	 */
5	
6	//! Unified Vector Addition Example
7	//!
8	//! THIS IS THE GOAL: Single file, single compilation, no cfg splits.
9	//!
10	//! Build and run with:
11	//!   cargo oxide run vecadd
12	//!
13	//! What happens:
14	//! 1. rustc parses this file, generates MIR for everything
15	//! 2. rustc-codegen-cuda intercepts codegen:
16	//!    - Finds `cuda_oxide_kernel_<hash>_vecadd` (from #[kernel])
17	//!    - Routes it to mir-importer → PTX
18	//!    - Routes `main` and other host code to standard LLVM
19	//! 3. Final binary has both host code and embedded PTX
20	
21	// No #![cfg_attr(cuda_device, no_std)] - this compiles as ONE unit!
22	
23	use cuda_core::{CudaContext, DeviceBuffer, LaunchConfig};
24	use cuda_device::{DisjointSlice, cuda_module, kernel, thread};
25	
26	// =============================================================================
27	// KERNEL - This gets compiled to PTX by rustc-codegen-cuda
28	// =============================================================================
29	
30	/// Vector addition kernel: c[i] = a[i] + b[i]
31	///
32	/// This function exists in BOTH host MIR and device PTX:
33	/// - Host: The function body is never called, but types are checked
